const emailBody = $json["textPlain"] || "";

// Helper function to match patterns
function matchFirst(patterns) {
  for (const pattern of patterns) {
    const match = emailBody.match(pattern);
    if (match) return match[1];
  }
  return null;
}

// Detect user name
const userName = matchFirst([
  /user[:\s*]*([a-zA-Z0-9._-]+)/i,
  /userName\s+([a-zA-Z0-9._-]+)/i
]);

// Detect new username for updates
const newUserName = matchFirst([
  /newusername[:\s*]*([a-zA-Z0-9._-]+)/i,
  /new user name\s+([a-zA-Z0-9._-]+)/i
]);

// Detect group name
const groupName = matchFirst([
  /group[:\s*]*([a-zA-Z0-9._-]+)/i,
  /groupname\s+([a-zA-Z0-9._-]+)/i
]);

// Detect new group name for updates
const newGroupName = matchFirst([
  /newgroupname[:\s*]*([a-zA-Z0-9._-]+)/i,
  /new group name\s+([a-zA-Z0-9._-]+)/i
]);

// Decide task type
let task_type = null;
if (/create user/i.test(emailBody)) task_type = "create_user";
else if (/delete user/i.test(emailBody)) task_type = "delete_user";
else if (/Add user /i.test(emailBody)) task_type = "add_user_to_group";
else if (/get user/i.test(emailBody)) task_type = "get_user";
else if (/get many user/i.test(emailBody)) task_type = "get_many_user";
else if (/remove user/i.test(emailBody)) task_type = "remove_user_from_group";
else if (/update user/i.test(emailBody)) task_type = "update_user";
else if (/create group/i.test(emailBody)) task_type = "create_group";
else if (/delete group/i.test(emailBody)) task_type = "delete_group";
else if (/get group/i.test(emailBody)) task_type = "get_group";
else if (/get many groups/i.test(emailBody)) task_type = "get_many_groups";
else if (/update group/i.test(emailBody)) task_type = "update_group";
else {
  // Handle unrecognized commands
  throw new Error("Unrecognized command in email body.");
}

return [
  {
    json: {
      userName,
      newUserName,
      groupName,
      newGroupName,
      task_type
    }
  }
];

// This code is designed for a Function node in an n8n workflow.
// It generates a structured message (subject and body) for a notification node,
// such as email, Slack, or Telegram, based on the outcome of a preceding task.

// Retrieve variables passed from previous nodes.
// The taskType corresponds to the AWS IAM operation being performed.
const taskType = $json.task_type || "";
const userName = $json.UserName || "";
const groupName = $json.groupName || "";
// The error message, if the task failed. We'll use this to determine success or failure.
const errorMsg = $json.error || "";
// The status variable is not reliable, so we will determine the status based on the error message.
const status = errorMsg ? "fail" : "success";

// Map the task_type variable to a more readable string for the message.
const taskMap = {
  create_user: "Create User",
  delete_user: "Delete User",
  add_user_to_group: "Add User to Group",
  get_user: "Get User",
  get_many_users: "Get Many Users", 
  remove_user_from_group: "Remove User from Group",
  update_user: "Update User"
};

let message = "";

// Construct the message based on the status of the task.
// This logic correctly handles the 'continue if error' setting.
if (status === "success") {
  // If the status is 'success', create a positive message.
  // The 'taskMap' ensures a friendly, readable task name.
  message = `✅ ${taskMap[taskType] || "IAM Task"} completed successfully.\n`;
  if (userName) message += `User: ${userName}\n`;
  if (groupName) message += `Group: ${groupName}\n`;

  // Special handling for 'get_many_users' to include the list of users.
  if (taskType === "get_many_users" && $json.ResponseMetadata) {
    const users = $json.ResponseMetadata.Users || $json.ResponseMetadata.users || [];
    if (users.length > 0) {
      message += "\n--- Extracted Users ---\n";
      users.forEach(user => {
        message += `- Username: ${user.UserName}\n`;
        message += `  Create Date: ${new Date(user.CreateDate).toLocaleDateString()}\n`;
        message += `  User ID: ${user.UserId}\n`;
        message += `  ARN: ${user.Arn}\n\n`;
      });
      message += "-----------------------\n";
    } else {
      message += "No users found.\n";
    }
  }

} else {
  // If the status is anything other than 'success' (e.g., 'fail'),
  // create a clear failure message.
  message = `❌ ${taskMap[taskType] || "IAM Task"} failed.\n`;
  if (userName) message += `User: ${userName}\n`;
  if (groupName) message += `Group: ${groupName}\n`;
  // Include the specific error message for easy debugging.
  if (errorMsg) message += `Error: ${errorMsg}\n`;
}

// Return the structured object that can be used by a notification node.
return {
  json: {
    // The subject line clearly indicates success or failure.
    subject: `${status === "success" ? "Success" : "Failure"} - ${taskMap[taskType] || "IAM Task"}`,
    // The body contains the detailed message.
    body: message
  }
};

